import{_ as e,a,b as d,c as r,d as o}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"OneDrive 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/onedrive.md","filePath":"ko-KR/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"ko-KR/upload/onedrive.md"};function p(h,t,b,m,f,g){return n(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="onedrive-채널-추가" tabindex="-1">OneDrive 채널 추가 <a class="header-anchor" href="#onedrive-채널-추가" aria-label="Permalink to &quot;OneDrive 채널 추가&quot;">​</a></h1><p>OneDrive 채널은 Microsoft OneDrive를 ImgBed의 저장 위치로 사용합니다.</p><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>Microsoft 계정</td><td>OneDrive와 앱 등록에 사용</td></tr><tr><td>ImgBed 도메인</td><td>OAuth 콜백 URL에 사용</td></tr><tr><td>App registration</td><td>Client ID와 Client Secret 발급</td></tr><tr><td>Refresh Token</td><td>장기 접근에 사용</td></tr></tbody></table><h2 id="microsoft-entra-id-열기" tabindex="-1">Microsoft Entra ID 열기 <a class="header-anchor" href="#microsoft-entra-id-열기" aria-label="Permalink to &quot;Microsoft Entra ID 열기&quot;">​</a></h2><ol><li><code>portal.azure.com</code>을 엽니다.</li><li>상단 검색에서 <code>Microsoft Entra ID</code>를 찾습니다.</li><li><code>App registrations</code>로 이동합니다.</li><li><code>New registration</code>을 누릅니다.</li></ol><h2 id="앱-등록하기" tabindex="-1">앱 등록하기 <a class="header-anchor" href="#앱-등록하기" aria-label="Permalink to &quot;앱 등록하기&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>Name</td><td>예: <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>사용할 OneDrive 계정 유형에 맞게 선택</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://내도메인/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>개인 OneDrive만 사용할 경우 개인 Microsoft 계정용을 선택합니다. 개인과 조직 계정을 모두 지원하려면 둘 다 허용하는 유형을 선택합니다.</p><p><img src="'+e+'" alt="OneDrive 앱 등록" loading="lazy"></p><p>등록 후 <code>Application (client) ID</code>를 기록합니다. 조직 계정으로 사용할 경우 <code>Directory (tenant) ID</code>도 함께 기록합니다.</p><p><img src="'+a+'" alt="Application ID와 Tenant ID" loading="lazy"></p><h2 id="client-secret-만들기" tabindex="-1">Client Secret 만들기 <a class="header-anchor" href="#client-secret-만들기" aria-label="Permalink to &quot;Client Secret 만들기&quot;">​</a></h2><ol><li><code>Certificates &amp; secrets</code>를 엽니다.</li><li><code>New client secret</code>을 누릅니다.</li><li>이름과 만료 기간을 설정합니다.</li><li>생성 직후 <code>Value</code>를 복사합니다.</li></ol><p><img src="'+d+'" alt="Client Secret" loading="lazy"></p><p>이 값은 나중에 다시 볼 수 없는 경우가 많으니 바로 저장해 두세요.</p><h2 id="microsoft-graph-권한" tabindex="-1">Microsoft Graph 권한 <a class="header-anchor" href="#microsoft-graph-권한" aria-label="Permalink to &quot;Microsoft Graph 권한&quot;">​</a></h2><p><code>API permissions</code>에서 Microsoft Graph의 delegated permissions를 추가합니다.</p><table tabindex="0"><thead><tr><th>권한</th><th>용도</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>파일 업로드, 디렉터리 생성, 삭제</td></tr><tr><td><code>offline_access</code></td><td>Refresh Token 발급</td></tr><tr><td><code>User.Read</code></td><td>계정 정보와 용량 확인</td></tr></tbody></table><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>업로드 설정에서 <code>OneDrive</code>를 선택합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>채널 이름</td><td>예: <code>OneDrive Main</code></td></tr><tr><td>Client ID</td><td><code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>생성한 Secret의 Value</td></tr><tr><td>Tenant ID</td><td>아래 표 참고</td></tr><tr><td>Refresh Token</td><td>처음에는 비워 둠</td></tr><tr><td>루트 디렉터리</td><td>선택 사항. 보통 <code>imgbed</code></td></tr></tbody></table><p><img src="'+r+'" alt="OneDrive 설정" loading="lazy"></p><table tabindex="0"><thead><tr><th>계정 유형</th><th>Tenant ID</th></tr></thead><tbody><tr><td>개인 계정</td><td><code>consumers</code></td></tr><tr><td>개인 + 조직</td><td><code>common</code></td></tr><tr><td>특정 조직만</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h2 id="refresh-token-받기" tabindex="-1">Refresh Token 받기 <a class="header-anchor" href="#refresh-token-받기" aria-label="Permalink to &quot;Refresh Token 받기&quot;">​</a></h2><ol><li>ImgBed에서 <code>Token 가져오기</code>를 누릅니다.</li><li>저장소로 사용할 Microsoft 계정으로 로그인합니다.</li><li>권한을 허용합니다.</li><li>콜백 페이지에 표시된 <code>Refresh Token</code>을 복사합니다.</li><li>ImgBed로 돌아와 <code>Refresh Token</code> 칸에 붙여 넣습니다.</li></ol><p><img src="'+o+`" alt="Refresh Token" loading="lazy"></p><h2 id="빠른-절차" tabindex="-1">빠른 절차 <a class="header-anchor" href="#빠른-절차" aria-label="Permalink to &quot;빠른 절차&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>portal.azure.com 열기</span></span>
<span class="line"><span>-&gt; Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; App registrations</span></span>
<span class="line"><span>-&gt; New registration</span></span>
<span class="line"><span>-&gt; Web 콜백 URL 설정</span></span>
<span class="line"><span>-&gt; Application ID 복사</span></span>
<span class="line"><span>-&gt; Client Secret 생성</span></span>
<span class="line"><span>-&gt; Microsoft Graph 권한 추가</span></span>
<span class="line"><span>-&gt; ImgBed에 Client ID / Secret / Tenant ID 입력</span></span>
<span class="line"><span>-&gt; Token 가져오기</span></span>
<span class="line"><span>-&gt; Refresh Token 붙여 넣고 저장</span></span></code></pre></div>`,29)])])}const k=i(c,[["render",p]]);export{_ as __pageData,k as default};
